import React, { useState } from 'react';
import { useDispatch } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { login } from '../store/slices/authSlice';
import toast from 'react-hot-toast';

const DEMO_USERS = {
  admin:        { full_name:'Admin User',     role:'school_admin', school_name:'Sunrise High School' },
  principal:    { full_name:'Rajesh Kumar',   role:'principal',    school_name:'Sunrise High School' },
  teacher1:     { full_name:'Sunita Sharma',  role:'teacher',      school_name:'Sunrise High School' },
  accountant:   { full_name:'Kavita Mishra',  role:'accountant',   school_name:'Sunrise High School' },
  receptionist: { full_name:'Anjali Singh',   role:'receptionist', school_name:'Sunrise High School' },
  parent1:      { full_name:'Parent User',    role:'parent',       school_name:'Sunrise High School' },
};

const DEMO_PILLS = [
  ['principal','Principal'],
  ['teacher1','Teacher'],
  ['accountant','Accountant'],
  ['parent1','Parent'],
];

export default function Login() {
  const [creds, setCreds] = useState({ username: 'admin', password: 'admin123' });
  const [loading, setLoading] = useState(false);
  const dispatch = useDispatch();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    // First try real backend
    const res = await dispatch(login(creds));

    if (login.fulfilled.match(res)) {
      toast.success(`Welcome back, ${res.payload.user?.full_name || 'User'}! 👋`);
      navigate('/');
      setLoading(false);
      return;
    }

    // Backend failed — try offline mock login
    const mockUser = DEMO_USERS[creds.username];
    if (mockUser && creds.password === 'admin123') {
      // Store mock session
      localStorage.setItem('mock_user', JSON.stringify(mockUser));
      localStorage.setItem('accessToken', 'mock_token_' + creds.username);
      // Manually set auth state
      dispatch({
        type: 'auth/login/fulfilled',
        payload: {
          user: { ...mockUser, id: 'mock-id', username: creds.username },
          accessToken: 'mock_token_' + creds.username,
          refreshToken: 'mock_refresh',
        }
      });
      toast.success(`Welcome back, ${mockUser.full_name}! 👋 (Demo mode)`);
      navigate('/');
    } else {
      toast.error('Invalid username or password. Try: admin / admin123');
    }

    setLoading(false);
  };

  const inp = {
    width:'100%', padding:'10px 14px',
    border:'1.5px solid #E5E7EB', borderRadius:8,
    fontSize:13, outline:'none', fontFamily:'inherit',
    transition:'border-color .15s',
  };

  return (
    <div style={{ minHeight:'100vh', background:'#1E1B4B', display:'flex', alignItems:'center', justifyContent:'center', padding:16 }}>
      {/* Background glow */}
      <div style={{ position:'absolute', inset:0, background:'radial-gradient(ellipse at 30% 50%, rgba(167,139,250,.15) 0%, transparent 60%)', pointerEvents:'none' }}/>

      <div style={{ background:'#fff', borderRadius:20, padding:36, width:400, maxWidth:'100%', boxShadow:'0 25px 60px rgba(0,0,0,.25)', position:'relative', zIndex:1 }}>

        {/* Logo */}
        <div style={{ textAlign:'center', marginBottom:28 }}>
          <div style={{ width:56, height:56, background:'linear-gradient(135deg,#A78BFA,#F59E0B)', borderRadius:16, display:'flex', alignItems:'center', justifyContent:'center', fontSize:26, margin:'0 auto 12px', boxShadow:'0 8px 20px rgba(167,139,250,.4)' }}>🏫</div>
          <div style={{ fontSize:22, fontWeight:700, color:'#1E1B4B' }}>EduManage</div>
          <div style={{ fontSize:12, color:'#9CA3AF', marginTop:3 }}>School Management System</div>
        </div>

        <form onSubmit={handleSubmit}>
          {/* Username */}
          <div style={{ marginBottom:14 }}>
            <label style={{ display:'block', fontSize:11, fontWeight:700, color:'#4B5563', textTransform:'uppercase', letterSpacing:'.06em', marginBottom:6 }}>Username</label>
            <input
              value={creds.username}
              onChange={e => setCreds({ ...creds, username: e.target.value })}
              placeholder="Enter username"
              style={inp}
              onFocus={e => e.target.style.borderColor='#7C3AED'}
              onBlur={e => e.target.style.borderColor='#E5E7EB'}
              autoComplete="username"
            />
          </div>

          {/* Password */}
          <div style={{ marginBottom:20 }}>
            <label style={{ display:'block', fontSize:11, fontWeight:700, color:'#4B5563', textTransform:'uppercase', letterSpacing:'.06em', marginBottom:6 }}>Password</label>
            <input
              type="password"
              value={creds.password}
              onChange={e => setCreds({ ...creds, password: e.target.value })}
              placeholder="Enter password"
              style={inp}
              onFocus={e => e.target.style.borderColor='#7C3AED'}
              onBlur={e => e.target.style.borderColor='#E5E7EB'}
              autoComplete="current-password"
            />
          </div>

          {/* Submit */}
          <button
            type="submit"
            disabled={loading}
            style={{
              width:'100%', padding:'12px',
              background: loading ? '#A78BFA' : '#1E1B4B',
              color:'#fff', border:'none', borderRadius:10,
              fontSize:14, fontWeight:700, cursor: loading ? 'wait' : 'pointer',
              transition:'all .15s', letterSpacing:'.02em',
            }}
          >
            {loading ? 'Signing in…' : 'Sign In →'}
          </button>
        </form>

        {/* Demo pills */}
        <div style={{ marginTop:20, border:'1.5px dashed #E5E7EB', borderRadius:12, padding:14 }}>
          <div style={{ fontSize:10, fontWeight:700, color:'#9CA3AF', textTransform:'uppercase', letterSpacing:'.08em', marginBottom:10 }}>
            Quick Demo Access
          </div>
          <div style={{ display:'flex', gap:7, flexWrap:'wrap' }}>
            {DEMO_PILLS.map(([u, label]) => (
              <button
                key={u}
                onClick={() => setCreds({ username: u, password: 'admin123' })}
                style={{
                  padding:'4px 12px', background:'#EDE9F8',
                  border:'1px solid #C4B5FD', borderRadius:20,
                  fontSize:11, fontWeight:600, color:'#1E1B4B', cursor:'pointer',
                  transition:'all .12s',
                }}
                onMouseEnter={e => { e.target.style.background='#1E1B4B'; e.target.style.color='#fff'; }}
                onMouseLeave={e => { e.target.style.background='#EDE9F8'; e.target.style.color='#1E1B4B'; }}
              >
                {label}
              </button>
            ))}
          </div>
          <div style={{ fontSize:10, color:'#9CA3AF', marginTop:10 }}>
            💡 All accounts use password: <strong>admin123</strong>
          </div>
        </div>

        {/* Info */}
        <div style={{ marginTop:14, padding:'10px 12px', background:'#F0FDF4', borderRadius:8, border:'1px solid #BBF7D0', fontSize:11, color:'#166534' }}>
          ✅ Works with or without backend — demo data loads automatically
        </div>
      </div>
    </div>
  );
}
